from behave import given, when, then
from selenium import webdriver
from selenium.webdriver.common.by import By
from selenium.webdriver.support.ui import WebDriverWait
from selenium.webdriver.support import expected_conditions as EC
import time

file_path = "index.html"

@given("the Movie Seat Booking page is loaded")
def step_given_page_loaded(context):
    context.driver = webdriver.Chrome()
    context.driver.get(f"file://index.html")
    time.sleep(1)

@given('the seat with data-testid "seat-1-1" is available')
def step_given_seat_available(context):
    seat = WebDriverWait(context.driver, 10).until(
        EC.presence_of_element_located((By.CSS_SELECTOR, "[data-testid='seat-1-1']"))
    )
    assert not seat.get_attribute("class").split().__contains__("occupied"), "Seat is occupied"
    time.sleep(1)

@when('the user clicks on the seat with data-testid "seat-1-1"')
def step_when_user_clicks_seat(context):
    seat = WebDriverWait(context.driver, 10).until(
        EC.element_to_be_clickable((By.CSS_SELECTOR, "[data-testid='seat-1-1']"))
    )
    seat.click()
    time.sleep(1)

@then('the seat with data-testid "seat-1-1" should be marked as selected')
def step_then_seat_marked_selected(context):
    seat = WebDriverWait(context.driver, 10).until(
        EC.presence_of_element_located((By.CSS_SELECTOR, "[data-testid='seat-1-1']"))
    )
    assert "selected" in seat.get_attribute("class").split(), "Seat is not marked as selected"
    time.sleep(1)

@then('the selected seat count should be updated to "1"')
def step_then_selected_seat_count_updated(context):
    count_element = WebDriverWait(context.driver, 10).until(
        EC.presence_of_element_located((By.CSS_SELECTOR, "[data-testid='selected-count']"))
    )
    assert count_element.text.strip() == "1", f"Expected seat count to be '1', but got '{count_element.text.strip()}'"
    time.sleep(1)

@then('the total price should reflect the selected movie price times the number of selected seats')
def step_then_total_price_updated(context):
    total_element = WebDriverWait(context.driver, 10).until(
        EC.presence_of_element_located((By.CSS_SELECTOR, "[data-testid='total-price']"))
    )
    movie_select = context.driver.find_element(By.CSS_SELECTOR, "[data-testid='movie-select']")
    ticket_price = int(movie_select.get_attribute("value"))
    expected_total_price = ticket_price * 1
    assert total_element.text.strip() == str(expected_total_price), f"Expected total price to be '{expected_total_price}', but got '{total_element.text.strip()}'"
    time.sleep(1)

def after_scenario(context, scenario):
    context.driver.quit()

