    )
    assert count_element.text.strip() == "1", f"Expected seat count to be '1', but got '{count_element.text.strip()}'"
    time.sleep(1)

@then('the total price should reflect the selected movie price times the number of selected seats')
def step_then_total_price_should_reflect_selected_movie_price(context):
    total_element = WebDriverWait(context.driver, 10).until(
        EC.presence_of_element_located((By.CSS_SELECTOR, "[data-testid='total-price']"))
    )
    movie_select = context.driver.find_element(By.CSS_SELECTOR, "[data-testid='movie-select']")
    ticket_price = int(movie_select.find_element(By.CSS_SELECTOR, "option:checked").get_attribute("value"))
    expected_total_price = ticket_price * 1  # 1 seat selected
    assert int(total_element.text.strip()) == expected_total_price, f"Expected total price to be '{expected_total_price}', but got '{total_element.text.strip()}'"
    time.sleep(1)

def after_scenario(context, scenario):
