    toggle_button = WebDriverWait(context.driver, 10).until(
        EC.element_to_be_clickable((By.CSS_SELECTOR, "[data-testid='toggle-button']"))
    )
    toggle_button.click()
    time.sleep(1)  # Allow time for the toggle action to take effect


@given('the text box with data-testid "text-box" is visible')
def step_given_text_box_visible(context):
