from behave import given, when, then
from selenium import webdriver
from selenium.webdriver.common.by import By
from selenium.webdriver.support.ui import WebDriverWait
from selenium.webdriver.support import expected_conditions as EC
import time

file_path = "index.html"

def is_active(element):
    """Helper function to check if the box is visually highlighted."""
    class_list = element.get_attribute("class").split()
    return "active" in class_list

@given("the webpage is loaded and all predefined phrase boxes are displayed in the main section")
def step_given_webpage_loaded(context):
    context.driver = webdriver.Chrome()  # Initialize the WebDriver
    context.driver.get(f"file://index.html")  # Load the test page
    WebDriverWait(context.driver, 10).until(
        EC.presence_of_element_located((By.CSS_SELECTOR, "main .box"))
    )  # Wait for the predefined phrase boxes to be displayed

@when('the user clicks on the box containing the text "{text}"')
def step_when_user_clicks_box(context, text):
    boxes = context.driver.find_elements(By.CSS_SELECTOR, "main .box")
    target_box = None
    for box in boxes:
        box_text = box.text.strip()
        print(box_text)
        if text.strip().lower() in box_text.lower():
            target_box = box
            break
    assert target_box is not None, f"Box with text '{text}' not found"
    WebDriverWait(context.driver, 10).until(EC.element_to_be_clickable(target_box))
    target_box.click()  # Click the box

@then('the system should read aloud the text "{text}"')
def step_then_system_reads_text(context, text):
    # Validate that the specified text is set in the SpeechSynthesisUtterance
    pass

@then('the box should visually highlight by adding the "active" class')
def step_then_box_highlights(context):
    active_boxes = [box for box in context.driver.find_elements(By.CSS_SELECTOR, "main .box") if is_active(box)]
    assert len(active_boxes) > 0, "Expected at least one box to be visually highlighted"

@then('the highlight should disappear after 800 milliseconds')
def step_then_highlight_disappears(context):
    time.sleep(0.8)  # Wait for 800 milliseconds
    active_boxes = [box for box in context.driver.find_elements(By.CSS_SELECTOR, "main .box") if is_active(box)]
    assert len(active_boxes) == 0, "Expected the highlight to disappear"

# Teardown step to close the browser after the test
def after_scenario(context, scenario):
    context.driver.quit()

