from behave import given, when, then
from selenium import webdriver
from selenium.webdriver.common.by import By
from selenium.webdriver.support.ui import WebDriverWait
from selenium.webdriver.support import expected_conditions as EC
import time

file_path = "index.html"

def is_expanded(element):
    aria = element.get_attribute("aria-expanded")
    if aria is not None:
        return aria == "true"
    class_list = element.get_attribute("class").split()
    if any(cls in class_list for cls in ["expanded", "open", "show"]):
        return True
    data_expanded = element.get_attribute("data-expanded")
    if data_expanded is not None:
        return data_expanded == "true"
    return element.is_displayed()

@given('the webpage is loaded')
def step_given_webpage_loaded(context):
    context.driver = webdriver.Chrome()
    context.driver.get(f"file://index.html")
    time.sleep(1)

@given('the user has searched for a word and the result card is displayed with data-testid "result-card"')
def step_given_result_card_displayed(context):
    search_input = WebDriverWait(context.driver, 10).until(
        EC.visibility_of_element_located((By.CSS_SELECTOR, "[data-testid='search-input']"))
    )
    search_input.send_keys("example")
    search_button = context.driver.find_element(By.CSS_SELECTOR, "[data-testid='search-button']")
    search_button.click()
    time.sleep(1)
    result_card = WebDriverWait(context.driver, 10).until(
        EC.visibility_of_element_located((By.CSS_SELECTOR, "[data-testid='result-card']"))
    )
    assert result_card.is_displayed(), "Result card is not displayed"

@when('the user clicks the bookmark icon with data-testid "bookmark-icon"')
def step_when_click_bookmark_icon(context):
    bookmark_icon = WebDriverWait(context.driver, 10).until(
        EC.element_to_be_clickable((By.CSS_SELECTOR, "[data-testid='bookmark-icon']"))
    )
    bookmark_icon.click()
    time.sleep(1)
    # Verify the bookmark icon changes state to indicate the word is bookmarked
    icon_class = bookmark_icon.find_element(By.TAG_NAME, "i").get_attribute("class")
    assert "bi-bookmark-check-fill" in icon_class, "Bookmark icon did not change state"

@then('the user clicks the bookmark word list show button with data-testid "bookmark-button" to show the bookmarked words')
def step_then_click_bookmark_button(context):
    bookmark_button = WebDriverWait(context.driver, 10).until(
        EC.element_to_be_clickable((By.CSS_SELECTOR, "[data-testid='bookmark-button']"))
    )
    bookmark_button.click()
    time.sleep(1)

@then('the word should be added to the list of bookmarked words in the offcanvas section with data-testid "bookmarked-words-list"')
def step_then_verify_bookmarked_words_list(context):
    bookmarked_words_list = WebDriverWait(context.driver, 10).until(
        EC.visibility_of_element_located((By.CSS_SELECTOR, "[data-testid='bookmarked-words-list']"))
    )
    # Extract all bookmarked words from the list
    bookmarked_words_items = bookmarked_words_list.find_elements(By.TAG_NAME, "li")
    bookmarked_words = [word.text.lower() for word in bookmarked_words_items]

    assert "example".lower() in bookmarked_words, "The word 'example' is not in the bookmarked words list"

def after_scenario(context, scenario):
    context.driver.quit()

